def _env_bool(name: str, default: bool = False) -> bool:
    """Parse a boolean from environment variables."""
    val = os.getenv(name)
    if val is None:
        return default
    val = val.strip().lower()
    return val in {"1", "true", "yes", "y", "on"}


def _env_int(name: str, default: int) -> int:
    raw = os.getenv(name)
    if raw is None or raw == "":
        return default
    try:
        return int(raw.strip())
    except Exception:
        return default


def _env_float_value(name: str, default: float) -> float:
    raw = os.getenv(name)
    if raw is None or raw == "":
        return default
    try:
        return float(raw.strip())
    except Exception:
        return default


def _intish(value: Any) -> Optional[int]:
    """Best-effort coercion for values that may be int, float, or numeric strings.

    Returns None if value cannot be interpreted as an integer or is boolean/None.
    """
    try:
        # Reject None and booleans
        if value is None or isinstance(value, bool):
            return None
        # Numeric types are cast directly
        if isinstance(value, int):
            return value
        if isinstance(value, float):
            # Reject NaN
            if value != value:
                return None
            return int(value)
        if isinstance(value, str):
            s = value.strip()
            if not s:
                return None
            # If it's digits or +digits, cast directly
            if s.isdigit() or (s.startswith('+') and s[1:].isdigit()):
                return int(s)
            # If it's numeric with decimal, cast via float
            try:
                return int(float(s))
            except Exception:
                return None
    except Exception:
        return None
    return None


def _role_base_name(role_name: str) -> str:
    """Return the base role name without a trailing numeric suffix."""
    try:
        s = str(role_name)
        parts = s.split("_")
        if len(parts) >= 2 and parts[-1].isdigit():
            base = "_".join(parts[:-1]) or s
            return base
        return s
    except Exception:
        return str(role_name)


